import React, { useEffect, useState } from "react";
import Layout from "./../../components/shared/Layout/Layout";
import { useSelector } from "react-redux";
import API from "../../services/API";
import moment from "moment";

const bloodGroups = ["O+", "O-", "A+", "A-", "B+", "B-", "AB+", "AB-"];

const OrganisationPage = () => {
  const { user } = useSelector((state) => state.auth);
  const [orgs, setOrgs] = useState([]);
  const [camps, setCamps] = useState([]);
  const [availability, setAvailability] = useState([]);
  const [search, setSearch] = useState("");
  const [selectedOrg, setSelectedOrg] = useState(null);
  const [selectedBloodGroup, setSelectedBloodGroup] = useState("");
  const [requestQty, setRequestQty] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [showRequestForm, setShowRequestForm] = useState(false);

  const isHospital = user?.role === "hospital";
  const isDonor = user?.role === "donar";

  const getOrgs = async () => {
    try {
      const { data } = await API.get("/inventory/get-all-organisations");
      if (data?.success) setOrgs(data?.organisations);
    } catch (error) {
      console.log(error);
    }
  };

  const getCamps = async () => {
    try {
      const { data } = await API.get("/camp/get-all-camps");
      if (data?.success) setCamps(data?.camps);
    } catch (error) {
      console.log(error);
    }
  };

  const getAvailability = async () => {
    try {
      const { data } = await API.get("/inventory/get-blood-availability");
      if (data?.success) setAvailability(data?.availability);
    } catch (error) {
      console.log(error);
    }
  };

  useEffect(() => {
    getOrgs();
    getCamps();
    if (isHospital) getAvailability();
  }, [user]);

  const filteredOrgs = orgs.filter(
    (org) =>
      org.organisationName?.toLowerCase().includes(search.toLowerCase()) ||
      org.address?.toLowerCase().includes(search.toLowerCase()),
  );

  const getAvailabilityForOrg = (orgId) =>
    availability.find((a) => a.organisation._id === orgId);

  const getCampsForOrg = (orgId) =>
    camps.filter((c) => (c.organisation?._id || c.organisation) === orgId);

  const handleRequest = async () => {
    try {
      if (!selectedOrg || !selectedBloodGroup || !requestQty)
        return alert("Please fill all fields");
      setSubmitting(true);
      const { data } = await API.post("/inventory/create-inventory", {
        email: selectedOrg.email,
        organisation: selectedOrg._id,
        inventoryType: "out",
        bloodGroup: selectedBloodGroup,
        quantity: Number(requestQty),
      });
      if (data?.success) {
        alert(
          `✅ Successfully requested ${requestQty}ml of ${selectedBloodGroup} from ${selectedOrg.organisationName}!`,
        );
        setShowRequestForm(false);
        setSelectedOrg(null);
        setSelectedBloodGroup("");
        setRequestQty("");
        getAvailability();
      }
    } catch (error) {
      alert(error?.response?.data?.message || "Request failed");
    } finally {
      setSubmitting(false);
    }
  };

  const openRequest = (org, bloodGroup) => {
    setSelectedOrg(org);
    setSelectedBloodGroup(bloodGroup || "");
    setShowRequestForm(true);
    setTimeout(() => {
      document
        .getElementById("req-form-section")
        ?.scrollIntoView({ behavior: "smooth" });
    }, 100);
  };

  const totalAvailableAllOrgs = availability.reduce(
    (sum, a) => sum + a.totalAvailable,
    0,
  );
  const orgsWithBlood = availability.filter((a) => a.totalAvailable > 0).length;

  return (
    <Layout>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Syne:wght@600;700;800&family=DM+Sans:wght@300;400;500&display=swap');
        .org-page { font-family: 'DM Sans', sans-serif; }
        .org-title { font-family: 'Syne', sans-serif; font-size: 26px; font-weight: 700; color: #fff; margin-bottom: 4px; }
        .org-title span { background: linear-gradient(90deg, #c084fc, #f472b6); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; }
        .org-subtitle { font-size: 14px; color: rgba(255,255,255,0.4); margin-bottom: 24px; }

        /* Search */
        .org-search-row { display: flex; align-items: center; gap: 14px; margin-bottom: 28px; flex-wrap: wrap; }
        .org-search { flex: 1; min-width: 200px; max-width: 400px; padding: 12px 16px; background: rgba(255,255,255,0.05); border: 1.5px solid rgba(255,255,255,0.1); border-radius: 12px; color: #fff; font-size: 14px; font-family: 'DM Sans', sans-serif; outline: none; transition: all 0.2s; }
        .org-search:focus { border-color: #a855f7; background: rgba(168,85,247,0.08); }
        .org-search::placeholder { color: rgba(255,255,255,0.2); }

        /* Hospital stats */
        .hosp-stats { display: flex; gap: 14px; margin-bottom: 28px; flex-wrap: wrap; }
        .hosp-stat { flex: 1; min-width: 140px; padding: 18px 20px; border-radius: 16px; text-align: center; }
        .hosp-stat.purple { background: rgba(168,85,247,0.08); border: 1px solid rgba(168,85,247,0.25); }
        .hosp-stat.green { background: rgba(34,197,94,0.08); border: 1px solid rgba(34,197,94,0.25); }
        .hosp-stat.pink { background: rgba(236,72,153,0.08); border: 1px solid rgba(236,72,153,0.25); }
        .hosp-stat-num { font-family: 'Syne', sans-serif; font-size: 28px; font-weight: 800; color: #fff; }
        .hosp-stat-label { font-size: 12px; color: rgba(255,255,255,0.35); margin-top: 4px; }

        /* Request form */
        .req-form-section { background: rgba(168,85,247,0.07); border: 1.5px solid rgba(168,85,247,0.3); border-radius: 20px; padding: 24px; margin-bottom: 28px; animation: slideDown 0.3s ease; }
        @keyframes slideDown { from { opacity:0; transform:translateY(-10px); } to { opacity:1; transform:translateY(0); } }
        .req-form-title { font-family: 'Syne', sans-serif; font-size: 16px; font-weight: 700; color: #fff; margin-bottom: 6px; }
        .req-form-sub { font-size: 13px; color: rgba(255,255,255,0.4); margin-bottom: 18px; }
        .req-form-org { display: inline-flex; align-items: center; gap: 8px; padding: 8px 14px; border-radius: 10px; background: rgba(168,85,247,0.15); border: 1px solid rgba(168,85,247,0.3); font-size: 13px; color: #c084fc; font-weight: 600; margin-bottom: 18px; }
        .req-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 14px; margin-bottom: 18px; }
        @media(max-width:600px){ .req-grid { grid-template-columns: 1fr; } }
        .req-field label { display: block; font-size: 11px; font-weight: 600; color: rgba(255,255,255,0.4); text-transform: uppercase; letter-spacing: 0.8px; margin-bottom: 8px; }
        .req-field select, .req-field input { width: 100%; padding: 12px 14px; border-radius: 12px; background: rgba(255,255,255,0.06); border: 1.5px solid rgba(255,255,255,0.1); color: #fff; font-size: 14px; font-family: 'DM Sans', sans-serif; outline: none; transition: all 0.2s; box-sizing: border-box; }
        .req-field select option { background: #1a0030; color: #fff; }
        .req-field select:focus, .req-field input:focus { border-color: #a855f7; background: rgba(168,85,247,0.1); }
        .req-field input::placeholder { color: rgba(255,255,255,0.2); }
        .req-avail-hint { font-size: 12px; color: #4ade80; margin-top: 6px; }
        .req-actions { display: flex; gap: 12px; }
        .req-submit { padding: 12px 28px; border-radius: 12px; border: none; cursor: pointer; background: linear-gradient(135deg, #9333ea, #ec4899); color: white; font-size: 14px; font-weight: 600; font-family: 'DM Sans', sans-serif; transition: all 0.2s; }
        .req-submit:disabled { opacity: 0.6; cursor: not-allowed; }
        .req-cancel { padding: 12px 20px; border-radius: 12px; border: 1px solid rgba(255,255,255,0.1); background: transparent; color: rgba(255,255,255,0.5); font-size: 14px; cursor: pointer; font-family: 'DM Sans', sans-serif; }

        /* Org cards */
        .section-title { font-family: 'Syne', sans-serif; font-size: 17px; font-weight: 700; color: #fff; margin-bottom: 6px; }
        .section-sub { font-size: 13px; color: rgba(255,255,255,0.35); margin-bottom: 16px; }
        .org-count { font-size: 13px; color: rgba(255,255,255,0.3); margin-bottom: 16px; }
        .org-count span { color: #a855f7; font-weight: 600; }
        .org-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(320px, 1fr)); gap: 16px; }
        .org-card { background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.08); border-radius: 18px; padding: 22px; transition: all 0.2s; position: relative; overflow: hidden; }
        .org-card::before { content: ''; position: absolute; top: 0; left: 0; right: 0; height: 2px; background: linear-gradient(90deg, #9333ea, #ec4899); opacity: 0; transition: opacity 0.2s; }
        .org-card:hover { border-color: rgba(168,85,247,0.3); transform: translateY(-3px); box-shadow: 0 8px 28px rgba(0,0,0,0.3); }
        .org-card:hover::before { opacity: 1; }
        .org-card-top { display: flex; align-items: center; gap: 14px; margin-bottom: 16px; }
        .org-avatar { width: 44px; height: 44px; border-radius: 12px; flex-shrink: 0; background: linear-gradient(135deg, #9333ea, #ec4899); display: flex; align-items: center; justify-content: center; font-size: 20px; }
        .org-name { font-family: 'Syne', sans-serif; font-size: 15px; font-weight: 700; color: #fff; margin-bottom: 4px; }
        .org-badge { display: inline-block; padding: 2px 8px; border-radius: 6px; font-size: 10px; font-weight: 600; background: rgba(34,197,94,0.12); color: #4ade80; }
        .org-badge-hosp { display: inline-block; padding: 2px 8px; border-radius: 6px; font-size: 10px; font-weight: 600; background: rgba(99,102,241,0.15); color: #818cf8; }
        .org-divider { height: 1px; background: rgba(255,255,255,0.06); margin-bottom: 14px; }
        .org-detail { display: flex; align-items: flex-start; gap: 10px; margin-bottom: 10px; }
        .org-detail-icon { font-size: 14px; flex-shrink: 0; margin-top: 1px; }
        .org-detail-text { font-size: 13px; color: rgba(255,255,255,0.5); line-height: 1.4; }
        .org-detail-text a { color: #c084fc; text-decoration: none; }
        .org-detail-text a:hover { color: #f0abfc; }

        /* Blood availability grid inside org card */
        .blood-avail-label { font-size: 11px; font-weight: 600; color: rgba(255,255,255,0.3); text-transform: uppercase; letter-spacing: 0.8px; margin: 14px 0 10px; }
        .blood-avail-grid { display: grid; grid-template-columns: repeat(4, 1fr); gap: 8px; margin-bottom: 14px; }
        .blood-avail-pill { padding: 10px 6px; border-radius: 10px; text-align: center; cursor: pointer; transition: all 0.2s; }
        .blood-avail-pill.has-blood { background: rgba(168,85,247,0.1); border: 1px solid rgba(168,85,247,0.25); }
        .blood-avail-pill.has-blood:hover { background: rgba(168,85,247,0.22); border-color: rgba(168,85,247,0.5); transform: translateY(-1px); }
        .blood-avail-pill.no-blood { background: rgba(255,255,255,0.02); border: 1px solid rgba(255,255,255,0.05); cursor: default; }
        .pill-group { font-family: 'Syne', sans-serif; font-size: 13px; font-weight: 800; }
        .pill-group.has { color: #c084fc; }
        .pill-group.none { color: rgba(255,255,255,0.15); }
        .pill-qty { font-size: 10px; margin-top: 2px; }
        .pill-qty.has { color: rgba(255,255,255,0.5); }
        .pill-qty.none { color: rgba(255,255,255,0.1); }
        .blood-avail-hint { font-size: 11px; color: rgba(168,85,247,0.6); margin-bottom: 14px; }
        .org-total-badge { display: inline-flex; align-items: center; gap: 6px; padding: 4px 12px; border-radius: 8px; background: rgba(34,197,94,0.1); border: 1px solid rgba(34,197,94,0.2); font-size: 11px; color: #4ade80; font-weight: 600; }
        .org-zero-badge { display: inline-flex; align-items: center; gap: 6px; padding: 4px 12px; border-radius: 8px; background: rgba(239,68,68,0.08); border: 1px solid rgba(239,68,68,0.15); font-size: 11px; color: #f87171; font-weight: 600; }

        /* Donor camps */
        .all-camps-section { margin-bottom: 36px; }
        .camps-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(270px, 1fr)); gap: 14px; }
        .camp-card { background: rgba(168,85,247,0.07); border: 1px solid rgba(168,85,247,0.2); border-radius: 16px; padding: 18px; transition: all 0.2s; }
        .camp-card:hover { border-color: rgba(168,85,247,0.4); transform: translateY(-2px); }
        .camp-card-top { display: flex; align-items: center; gap: 10px; margin-bottom: 10px; }
        .camp-icon { font-size: 20px; }
        .camp-name { font-family: 'Syne', sans-serif; font-size: 14px; font-weight: 700; color: #fff; }
        .camp-active-badge { display: inline-block; padding: 2px 8px; border-radius: 6px; font-size: 10px; font-weight: 600; background: rgba(34,197,94,0.15); color: #4ade80; margin-left: 6px; }
        .camp-detail { font-size: 12px; color: rgba(255,255,255,0.45); margin-bottom: 4px; }
        .camp-org-tag { margin-top: 10px; padding: 6px 10px; border-radius: 8px; background: rgba(255,255,255,0.05); border: 1px solid rgba(255,255,255,0.08); font-size: 11px; color: rgba(255,255,255,0.5); display: flex; align-items: center; gap: 6px; }
        .camp-org-tag strong { color: #c084fc; }
        .camp-verified { font-size: 10px; color: #4ade80; margin-left: auto; }
        .no-camps { text-align: center; padding: 30px; color: rgba(255,255,255,0.2); font-size: 13px; }
        .org-camps-label { font-size: 11px; font-weight: 600; color: rgba(255,255,255,0.3); text-transform: uppercase; letter-spacing: 0.8px; margin: 14px 0 8px; }
        .org-camp-pill { display: flex; align-items: flex-start; gap: 8px; padding: 10px 12px; border-radius: 10px; margin-bottom: 8px; background: rgba(168,85,247,0.08); border: 1px solid rgba(168,85,247,0.18); }
        .org-camp-pill-icon { font-size: 14px; flex-shrink: 0; margin-top: 1px; }
        .org-camp-pill-name { font-size: 13px; font-weight: 600; color: rgba(255,255,255,0.8); margin-bottom: 2px; }
        .org-camp-pill-detail { font-size: 11px; color: rgba(255,255,255,0.35); }
        .org-no-camps { font-size: 12px; color: rgba(255,255,255,0.2); padding: 10px 0; }
        .org-copy-btn { width: 100%; margin-top: 14px; padding: 10px; border-radius: 11px; border: 1px solid rgba(168,85,247,0.3); background: rgba(168,85,247,0.1); color: #c084fc; font-size: 13px; font-weight: 600; font-family: 'DM Sans', sans-serif; cursor: pointer; transition: all 0.2s; }
        .org-copy-btn:hover { background: rgba(168,85,247,0.2); }
        .org-empty { text-align: center; padding: 80px 20px; }
        .org-empty-icon { font-size: 48px; margin-bottom: 12px; }
        .org-empty-text { font-size: 15px; color: rgba(255,255,255,0.3); }
      `}</style>

      <div className="org-page">
        {/* TITLE */}
        {isHospital ? (
          <>
            <div className="org-title">
              Live Blood <span>Availability</span> 🩸
            </div>
            <div className="org-subtitle">
              See exactly how much blood each organisation has right now — click
              any blood group to request it instantly
            </div>
          </>
        ) : (
          <>
            <div className="org-title">
              Blood Banks & <span>Organisations</span> 🏢
            </div>
            <div className="org-subtitle">
              Find a blood bank or camp near you — all verified on HemoLink
            </div>
          </>
        )}

        {/* HOSPITAL STATS */}
        {isHospital && availability.length > 0 && (
          <div className="hosp-stats">
            <div className="hosp-stat purple">
              <div className="hosp-stat-num">{totalAvailableAllOrgs}</div>
              <div className="hosp-stat-label">
                Total ML Available Site-wide
              </div>
            </div>
            <div className="hosp-stat green">
              <div className="hosp-stat-num">{orgsWithBlood}</div>
              <div className="hosp-stat-label">Orgs With Blood Ready</div>
            </div>
            <div className="hosp-stat pink">
              <div className="hosp-stat-num">{orgs.length}</div>
              <div className="hosp-stat-label">Total Blood Banks</div>
            </div>
          </div>
        )}

        {/* REQUEST FORM */}
        {showRequestForm && selectedOrg && (
          <div className="req-form-section" id="req-form-section">
            <div className="req-form-title">🩸 Request Blood</div>
            <div className="req-form-sub">
              Fill in the details below — stock will be deducted from the
              organisation immediately
            </div>
            <div className="req-form-org">
              🏥 {selectedOrg.organisationName}
            </div>
            <div className="req-grid">
              <div className="req-field">
                <label>Blood Group</label>
                <select
                  value={selectedBloodGroup}
                  onChange={(e) => setSelectedBloodGroup(e.target.value)}
                >
                  <option value="">Select blood group</option>
                  {bloodGroups.map((bg) => {
                    const orgAvail = getAvailabilityForOrg(selectedOrg._id);
                    const bgData = orgAvail?.bloodData?.find(
                      (b) => b.bloodGroup === bg,
                    );
                    const avail = bgData?.available || 0;
                    return (
                      <option key={bg} value={bg} disabled={avail === 0}>
                        {bg} —{" "}
                        {avail > 0 ? `${avail}ml available` : "not available"}
                      </option>
                    );
                  })}
                </select>
                {selectedBloodGroup &&
                  (() => {
                    const orgAvail = getAvailabilityForOrg(selectedOrg._id);
                    const bgData = orgAvail?.bloodData?.find(
                      (b) => b.bloodGroup === selectedBloodGroup,
                    );
                    return bgData?.available > 0 ? (
                      <div className="req-avail-hint">
                        ✅ {bgData.available}ml available
                      </div>
                    ) : null;
                  })()}
              </div>
              <div className="req-field">
                <label>Quantity (ML)</label>
                <input
                  type="number"
                  placeholder="e.g. 500"
                  value={requestQty}
                  onChange={(e) => setRequestQty(e.target.value)}
                />
              </div>
            </div>
            <div className="req-actions">
              <button
                className="req-submit"
                onClick={handleRequest}
                disabled={submitting}
              >
                {submitting ? "Requesting..." : "Confirm Request →"}
              </button>
              <button
                className="req-cancel"
                onClick={() => {
                  setShowRequestForm(false);
                  setSelectedOrg(null);
                }}
              >
                Cancel
              </button>
            </div>
          </div>
        )}

        <input
          className="org-search"
          type="text"
          placeholder="🔍  Search by name or address..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          style={{
            marginBottom: 28,
            display: "block",
            width: "100%",
            maxWidth: 400,
          }}
        />

        {/* DONOR — CAMPS SECTION */}
        {isDonor && (
          <div className="all-camps-section">
            <div className="section-title">🏕️ Active Blood Donation Camps</div>
            <div className="section-sub">
              All upcoming camps — each linked to a verified blood bank
            </div>
            {camps.length === 0 ? (
              <div className="no-camps">
                No active camps right now. Check back soon!
              </div>
            ) : (
              <div className="camps-grid">
                {camps.map((camp) => (
                  <div className="camp-card" key={camp._id}>
                    <div className="camp-card-top">
                      <span className="camp-icon">🏕️</span>
                      <div className="camp-name">
                        {camp.campName}
                        <span className="camp-active-badge">Active</span>
                      </div>
                    </div>
                    <div className="camp-detail">📍 {camp.address}</div>
                    <div className="camp-detail">
                      📅 {moment(camp.date).format("DD MMM YYYY")} &nbsp; 🕐{" "}
                      {camp.time}
                    </div>
                    <div className="camp-org-tag">
                      🏥 Organised by:{" "}
                      <strong>
                        {camp.organisation?.organisationName || "—"}
                      </strong>
                      <span className="camp-verified">✅ Verified</span>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        {/* ORG CARDS */}
        <div className="section-title">
          {isHospital
            ? "🏥 Blood Banks & Live Stock"
            : "🏢 Registered Blood Banks"}
        </div>
        <div className="section-sub" style={{ marginBottom: 16 }}>
          {isHospital
            ? "Click any purple blood group pill to instantly open a request for that blood type"
            : "Each blood bank shows their contact info and active camps"}
        </div>

        {filteredOrgs.length > 0 && (
          <div className="org-count">
            Showing <span>{filteredOrgs.length}</span> organisation
            {filteredOrgs.length !== 1 ? "s" : ""}
          </div>
        )}

        {filteredOrgs.length === 0 ? (
          <div className="org-empty">
            <div className="org-empty-icon">🏢</div>
            <div className="org-empty-text">
              {orgs.length === 0
                ? "No organisations registered yet"
                : "No results found"}
            </div>
          </div>
        ) : (
          <div className="org-grid">
            {filteredOrgs.map((org) => {
              const orgAvail = getAvailabilityForOrg(org._id);
              const orgCamps = getCampsForOrg(org._id);
              return (
                <div className="org-card" key={org._id}>
                  <div className="org-card-top">
                    <div className="org-avatar">🏥</div>
                    <div>
                      <div className="org-name">{org.organisationName}</div>
                      {isHospital ? (
                        orgAvail?.totalAvailable > 0 ? (
                          <span className="org-total-badge">
                            ✅ {orgAvail.totalAvailable}ml available
                          </span>
                        ) : (
                          <span className="org-zero-badge">
                            ⚠️ No stock right now
                          </span>
                        )
                      ) : (
                        <span className="org-badge">Accepting Donations</span>
                      )}
                    </div>
                  </div>
                  <div className="org-divider" />

                  {org.email && (
                    <div className="org-detail">
                      <span className="org-detail-icon">✉️</span>
                      <div className="org-detail-text">
                        <a href={`mailto:${org.email}`}>{org.email}</a>
                      </div>
                    </div>
                  )}
                  {org.phone && (
                    <div className="org-detail">
                      <span className="org-detail-icon">📞</span>
                      <div className="org-detail-text">{org.phone}</div>
                    </div>
                  )}
                  {org.address && (
                    <div className="org-detail">
                      <span className="org-detail-icon">📍</span>
                      <div className="org-detail-text">{org.address}</div>
                    </div>
                  )}

                  {/* HOSPITAL — live blood availability grid */}
                  {isHospital && orgAvail && (
                    <>
                      <div className="blood-avail-label">
                        Live Blood Stock — click to request
                      </div>
                      <div className="blood-avail-grid">
                        {orgAvail.bloodData.map((b) =>
                          b.available > 0 ? (
                            <div
                              className="blood-avail-pill has-blood"
                              key={b.bloodGroup}
                              onClick={() => openRequest(org, b.bloodGroup)}
                              title={`Click to request ${b.bloodGroup}`}
                            >
                              <div className="pill-group has">
                                {b.bloodGroup}
                              </div>
                              <div className="pill-qty has">
                                {b.available}ml
                              </div>
                            </div>
                          ) : (
                            <div
                              className="blood-avail-pill no-blood"
                              key={b.bloodGroup}
                            >
                              <div className="pill-group none">
                                {b.bloodGroup}
                              </div>
                              <div className="pill-qty none">0ml</div>
                            </div>
                          ),
                        )}
                      </div>
                      {orgAvail.totalAvailable > 0 && (
                        <div className="blood-avail-hint">
                          💡 Tap any purple pill above to request that blood
                          group
                        </div>
                      )}
                    </>
                  )}

                  {/* DONOR — show camps */}
                  {isDonor && (
                    <>
                      <div className="org-camps-label">
                        🏕️ Camps by this organisation
                      </div>
                      {orgCamps.length === 0 ? (
                        <div className="org-no-camps">
                          No active camps right now
                        </div>
                      ) : (
                        orgCamps.map((camp) => (
                          <div className="org-camp-pill" key={camp._id}>
                            <span className="org-camp-pill-icon">🏕️</span>
                            <div>
                              <div className="org-camp-pill-name">
                                {camp.campName}
                              </div>
                              <div className="org-camp-pill-detail">
                                📍 {camp.address} &nbsp;|&nbsp; 📅{" "}
                                {moment(camp.date).format("DD MMM")} at{" "}
                                {camp.time}
                              </div>
                            </div>
                          </div>
                        ))
                      )}
                      <button
                        className="org-copy-btn"
                        onClick={() => {
                          navigator.clipboard?.writeText(org.email);
                          alert(`${org.organisationName}'s email copied!`);
                        }}
                      >
                        📋 Copy Email
                      </button>
                    </>
                  )}
                </div>
              );
            })}
          </div>
        )}
      </div>
    </Layout>
  );
};

export default OrganisationPage;
